public class BuilderManager : MonoBehaviour {
    private Queue<Building> constructionQueue = new Queue<Building>();
    private Queue<Building> destroyedQueue = new Queue<Building>();
    private List<Builder> availableBuilders = new List<Builder>();
    private List<Builder> busyBuilders = new List<Builder>();
    private bool isNightTime = false;

    void Start() {
        // Subscribe to day/night events
        GameManager.Instance.OnDayStart += DayAction;
        GameManager.Instance.OnNightStart += NightAction;
    }

    void Update() {
        if (!isNightTime && availableBuilders.Count > 0) {
            AssignBuildersToConstruction();
        }
    }

    public void AddBuildingToQueue(Building building) {
        constructionQueue.Enqueue(building);
    }

    public void AddBuilder(Builder builder) {
        availableBuilders.Add(builder);
    }

    private void AssignBuildersToConstruction() {
        while (availableBuilders.Count > 0 && (destroyedQueue.Count > 0 || constructionQueue.Count > 0)) {
            Building buildingToConstruct = destroyedQueue.Count > 0 ? destroyedQueue.Dequeue() : constructionQueue.Dequeue();
            Builder builder = availableBuilders[0];
            availableBuilders.RemoveAt(0);
            busyBuilders.Add(builder);
            StartCoroutine(ConstructBuilding(builder, buildingToConstruct));
        }
    }

    private IEnumerator ConstructBuilding(Builder builder, Building building) {
        builder.MarkAsBusy();
        while (building.GetConstructionProgress() < 100 && !isNightTime) {
            building.Construct(); // Simulates the construction over time.
            yield return new WaitForSeconds(1f); // Wait time simulating construction work in progress.
        }
        if (building.GetConstructionProgress() >= 100) {
            building.MarkAsComplete();
            busyBuilders.Remove(builder);
            builder.MarkAsAvailable();
            availableBuilders.Add(builder);
        }
    }

    private void DayAction() {
        isNightTime = false;
        foreach (Builder builder in busyBuilders) {
            // Resume construction if it was paused due to night time.
            StartConstruction(builder);
        }
    }

    private void NightAction() {
        isNightTime = true;
        foreach (Builder builder in busyBuilders) {
            builder.GoToHouse(); // Builder goes home for the night.
        }
    }

    public void BuildingDestroyed(Building building) {
        destroyedQueue.Enqueue(building);
        building.NotifyBuilderManager();
    }

    void OnDestroy() {
        // Unsubscribe to prevent memory leaks.
        GameManager.Instance.OnDayStart -= DayAction;
        GameManager.Instance.OnNightStart -= NightAction;
    }

    private void StartConstruction(Builder builder) {
        // Find the building associated with the builder.
        Building building = /* logic to find the builder's assigned building */
        StartCoroutine(ConstructBuilding(builder, building));
    }
}

