    // Get existing progress and calculate elapsed time based on it.
    float buildTime = building.GetBuildDuration();
    float initialProgress = building.GetConstructionProgress(); // Get the initial progress in the range 0-1.
    float elapsedTime = initialProgress * buildTime; // Convert back to time.
